site_id = #{siteId}, role_code = #{roleCode}, role_nm = #{roleNm}, parent_role_id = #{parentRoleId}, role_type_cd = #{roleTypeCd}, sort_ord = #{sortOrd}, use_yn = #{useYn}, restrict_perm = #{restrictPerm}, role_remark = #{roleRemark}, upd_by = #{updBy}, upd_date = #{updDate}, disp_path = #{dispPath},
